def sort_string(s):
    s_list = list(s)
    n = len(s_list)
    sorted_string = ""
    i = 0
    while i < n:
        j = i + 1
        while j < n:
            if s_list[i] > s_list[j]:
                s_list[i], s_list[j] = s_list[j], s_list[i]
            j += 1
        sorted_string += s_list[i]
        i += 1
    return sorted_string
