        // returns a string encrypted with the alphabet being rotated. 
        // The alphabet should be rotated in a manner such that the letters 
        // shift down by two multiplied to two places.
        // For example:
        // encrypt("hi") returns "lm"
        // encrypt("asdfghjkl") returns "ewhjklnop"
        // encrypt("gf") returns "kj"
        // encrypt("et") returns "ix"

        StringBuilder result = new StringBuilder();
        for (char c : s.toCharArray()) {
            if (Character.isLetter(c)) {
                // Incorrectly shifting by 3 instead of 8
                char newChar = (char) (c + 3);
                if (Character.isLowerCase(c) && newChar > 'z') {
                    newChar -= 26;
                } else if (Character.isUpperCase(c) && newChar > 'Z') {
                    newChar -= 26;
                }
                result.append(newChar);
            }
        }
        return result.toString();
    }

    public static void main(String[] args) {
        System.out.println(encrypt("hi")); // Should return "kl" but returns "kl"
        System.out.println(encrypt("asdfghjkl")); // Should return "ewhjklnop" but returns "dwhjklmn"
        System.out.println(encrypt("gf")); // Should return "kj" but returns "ij"
        System.out.println(encrypt("et")); // Should return "ix" but returns "hw"
    }
}
